    acc.sum += curr;
    acc.min = curr < acc.min ? curr : acc.min;
    acc.max = curr > acc.max ? curr : acc.max;

    if (index === array.length - 1) {
      acc.average = acc.sum / array.length;
    }
    return acc;
  }, { sum: 0, min: Infinity, max: -Infinity, average: 0 });
};

